// Read inputs passed from the toolWorkflow caller
const input = $input.first().json;
const queryType = input.query_type || 'deal_health_all';
const dealId = input.deal_id || null;
const action = input.action || null;
const messageId = input.message_id || null;
const resolvedDealId = input.resolved_deal_id || null;
const resolution = input.resolution || 'confirmed';

let sql;

switch (queryType) {
  case 'deal_health_single':
    if (!dealId) throw new Error('deal_health_single requires deal_id');
    sql = `SELECT d.deal_id, d.company_name, d.salesforce_stage, d.deal_stage,
             d.deal_value_usd, d.close_date, d.forecast_category, d.deal_owner,
             dh.pain_score, dh.power_score, dh.vision_score, dh.value_score,
             dh.change_score, dh.control_score, dh.p2v2c2_total,
             dh.critical_activity_stage, dh.champion_name, dh.champion_title,
             dh.executive_sponsor_name, dh.executive_sponsor_title,
             dh.pe_sponsor_score,
             dh.dap_exists, dh.dap_agreed, dh.dap_status,
             dh.dap_milestones_complete, dh.dap_has_14_day_gap,
             dh.dap_next_milestone, dh.dap_next_milestone_date, dh.dap_summary,
             dh.risks, dh.next_step, dh.next_step_date,
             dh.call_summary, dh.internal_team_update,
             dh.trend_direction, dh.score_vs_previous, dh.scored_at
           FROM deals d
           LEFT JOIN LATERAL (
             SELECT * FROM deal_health WHERE deal_id = d.deal_id ORDER BY scored_at DESC LIMIT 1
           ) dh ON true
           WHERE d.deal_id = '${dealId}'
           LIMIT 1`;
    break;

  case 'deal_health_all':
    sql = `SELECT d.deal_id, d.company_name, d.deal_stage,
             d.deal_value_usd, d.forecast_category,
             dh.p2v2c2_total, dh.critical_activity_stage,
             dh.champion_name, dh.executive_sponsor_name,
             dh.next_step, dh.next_step_date, dh.trend_direction,
             dh.score_vs_previous, dh.scored_at
           FROM deals d
           LEFT JOIN LATERAL (
             SELECT * FROM deal_health WHERE deal_id = d.deal_id ORDER BY scored_at DESC LIMIT 1
           ) dh ON true
           WHERE d.is_active = true
           ORDER BY dh.p2v2c2_total DESC NULLS LAST`;
    break;

  case 'pipeline_summary':
    sql = `SELECT d.deal_stage, d.forecast_category,
             COUNT(*) AS deal_count,
             SUM(d.deal_value_usd) AS total_value,
             ROUND(AVG(dh.p2v2c2_total), 1) AS avg_p2v2c2,
             COUNT(CASE WHEN dh.trend_direction = 'declining' THEN 1 END) AS declining_deals
           FROM deals d
           LEFT JOIN LATERAL (
             SELECT * FROM deal_health WHERE deal_id = d.deal_id ORDER BY scored_at DESC LIMIT 1
           ) dh ON true
           WHERE d.is_active = true
           GROUP BY d.deal_stage, d.forecast_category
           ORDER BY d.deal_stage`;
    break;

  case 'attribution_queue':
    if (action === 'confirm_attribution') {
      if (!messageId) throw new Error('confirm_attribution requires message_id');
      sql = `UPDATE attribution_queue
             SET resolution = '${resolution}',
                 resolved_deal_id = ${resolvedDealId ? `'${resolvedDealId}'` : 'NULL'},
                 resolved_at = NOW()
             WHERE message_id = '${messageId}'
             RETURNING id, message_id, resolution, resolved_deal_id`;
    } else {
      sql = `SELECT id, message_id, sender_email, sender_domain, subject,
               ai_guess_deal_id, ai_guess_company, ai_confidence, doc_type, queued_at
             FROM attribution_queue
             WHERE resolution = 'pending'
             ORDER BY queued_at ASC
             LIMIT 20`;
    }
    break;

  case 'pending_drafts':
    sql = `SELECT ol.id, ol.deal_id, d.company_name, ol.output_type,
             ol.triggered_by, ol.sent_at, ol.subject,
             ol.full_content, ol.recipient_email, ol.recipient_name
           FROM outputs_log ol
           JOIN deals d ON d.deal_id = ol.deal_id
           WHERE ol.status = 'draft'
           ORDER BY ol.sent_at ASC`;
    break;


  case 'get_traces': {
    const sessionId = input.session_id || null;
    if (sessionId) {
      sql = `SELECT id, session_id, deal_id, user_input,
               LEFT(agent_output, 300) as agent_output_preview,
               think_steps, tool_calls,
               total_tokens, total_duration_ms, tools_called_count,
               status, created_at
             FROM agent_traces
             WHERE session_id = '${sessionId}'
             ORDER BY created_at DESC
             LIMIT 20`;
    } else {
      sql = `SELECT id, session_id, deal_id, user_input,
               LEFT(agent_output, 200) as agent_output_preview,
               think_steps, tool_calls,
               total_tokens, total_duration_ms,
               status, created_at
             FROM agent_traces
             ORDER BY created_at DESC
             LIMIT 10`;
    }
    break;
  }

  default:
    throw new Error(`Unknown query_type: ${queryType}`);
}

return [{ json: { query_type: queryType, sql, deal_id: dealId } }];

const rows = $input.all().map(item => item.json).filter(r => r && Object.keys(r).length > 0 && !Object.values(r).every(v => v === null || v === undefined));
const queryType = $('Code: Route Query').first().json.query_type;
const row_count = rows.length;

if (row_count === 0) {
  if (queryType === 'pending_drafts') return [{ json: { result: 'No pending drafts.' } }];
  if (queryType === 'attribution_queue') return [{ json: { result: 'Attribution queue is empty.' } }];
  return [{ json: { result: `No data found for query_type: ${queryType}` } }];
}

if (queryType === 'deal_health_single') {
  const d = rows[0];
