${d.call_summary || 'No summary available'}

### Internal Team Update
${d.internal_team_update || 'Not generated yet'}`;
  return [{ json: { result } }];
}

if (queryType === 'deal_health_all') {
  const lines = rows.map(d => {
    const total = d.p2v2c2_total !== null ? d.p2v2c2_total : '—';
    const trend = d.trend_direction === 'improving' ? '↑' : d.trend_direction === 'declining' ? '↓' : '→';
    const scored = d.scored_at ? new Date(d.scored_at).toISOString().split('T')[0] : 'never';
    return `| ${d.company_name} | ${d.deal_id} | ${d.deal_stage || '?'} | ${total}/30 | ${trend} | ${d.next_step ? d.next_step.slice(0,40) : '—'} | ${scored} |`;
  });
  const result = `## All Active Deals — P2V2C2 Dashboard

