  }).join('

');
  const result = `## Attribution Queue — ${realRows.length} Pending Item(s)

${items}

To confirm, tell me which deal each belongs to.`;
  return [{ json: { result } }];
}

if (queryType === 'pending_drafts') {
  const realRows = rows.filter(r => r.id != null);
