**Subject:** ${r.subject}`;
    if (r.recipient_name) entry += `
**To:** ${r.recipient_name} <${r.recipient_email || ''}>`;
    if (r.full_content) entry += `

${r.full_content}`;
    return entry;
  });
  const result = `PENDING_DRAFTS_COUNT:${realRows.length}

${items.join('

---

')}`;
  return [{ json: { result, pending_draft_count: realRows.length } }];
}

const r = rows[0];
const result = `Attribution updated: message_id ${r.message_id} resolved as ${r.resolution}, assigned to: ${r.resolved_deal_id || 'none'}.`;
return [{ json: { result } }];

